public static class SeedData
{
    public static async Task InitializeAsync(IServiceProvider serviceProvider)
    {
        var roleManager = serviceProvider.GetRequiredService<RoleManager<IdentityRole>>();
        var userManager = serviceProvider.GetRequiredService<UserManager<ApplicationUser>>();
        var db = serviceProvider.GetRequiredService<ApplicationDbContext>();

        // Create roles
        string[] roles = ["Dispatcher", "Customer"];
        foreach (var role in roles)
        {
            if (!await roleManager.RoleExistsAsync(role))
                await roleManager.CreateAsync(new IdentityRole(role));
        }

        // Create a demo dispatcher
        if (await userManager.FindByEmailAsync("dispatcher@shiptrack.com") is null)
        {
            var dispatcher = new ApplicationUser
            {
                UserName = "dispatcher@shiptrack.com",
                Email = "dispatcher@shiptrack.com",
                EmailConfirmed = true
            };
            await userManager.CreateAsync(dispatcher, "Dispatch1!");
            await userManager.AddToRoleAsync(dispatcher, "Dispatcher");
        }

        // Create a demo customer
        if (await userManager.FindByEmailAsync("customer@example.com") is null)
        {
            var customer = new ApplicationUser
            {
                UserName = "customer@example.com",
                Email = "customer@example.com",
                EmailConfirmed = true
            };
            await userManager.CreateAsync(customer, "Customer1!");
            await userManager.AddToRoleAsync(customer, "Customer");
        }

        // Seed sample shipments
        if (!db.Shipments.Any())
        {
            db.Shipments.AddRange(
                new Shipment
                {
                    TrackingNumber = "SHP-20260501-1001",
                    Origin = "New York, NY",
                    Destination = "Los Angeles, CA",
                    Status = (int)ShipmentStatus.InTransit,
                    CreatedAtUtc = DateTime.UtcNow.AddDays(-3),
                    EstimatedDeliveryUtc = DateTime.UtcNow.AddDays(2),
                    RecipientName = "Alice Johnson"
                },
                new Shipment
                {
                    TrackingNumber = "SHP-20260502-1042",
                    Origin = "Chicago, IL",
                    Destination = "Houston, TX",
                    Status = (int)ShipmentStatus.PickedUp,
                    CreatedAtUtc = DateTime.UtcNow.AddDays(-1),
                    EstimatedDeliveryUtc = DateTime.UtcNow.AddDays(4),
                    RecipientName = "Bob Smith"
                },
                new Shipment
                {
                    TrackingNumber = "SHP-20260503-2217",
                    Origin = "Seattle, WA",
                    Destination = "Miami, FL",
                    Status = (int)ShipmentStatus.OutForDelivery,
                    CreatedAtUtc = DateTime.UtcNow.AddDays(-5),
                    EstimatedDeliveryUtc = DateTime.UtcNow,
                    RecipientName = "Carol Davis"
                },
                new Shipment
                {
                    TrackingNumber = "SHP-20260504-3389",
                    Origin = "Denver, CO",
                    Destination = "Boston, MA",
                    Status = (int)ShipmentStatus.Delivered,
                    CreatedAtUtc = DateTime.UtcNow.AddDays(-7),
                    EstimatedDeliveryUtc = DateTime.UtcNow.AddDays(-2),
                    RecipientName = "Dan Wilson"
                },
                new Shipment
                {
                    TrackingNumber = "SHP-20260505-4456",
                    Origin = "San Francisco, CA",
                    Destination = "Phoenix, AZ",
                    Status = (int)ShipmentStatus.Pending,
                    CreatedAtUtc = DateTime.UtcNow,
                    EstimatedDeliveryUtc = DateTime.UtcNow.AddDays(5),
                    RecipientName = "Eve Martinez"
                }
            );
            await db.SaveChangesAsync();
        }
    }
}

