@page "/dispatcher"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Microsoft.AspNetCore.Authorization.Authorize(Roles = "Dispatcher")]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Dispatcher Dashboard</h1>

<div class="d-flex justify-content-between align-items-center mb-3">
    <div>
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <button class="btn btn-success" @onclick="ShowCreateForm">
        + New Shipment
    </button>
</div>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-header">Create New Shipment</div>
        <div class="card-body">
            <div class="row g-3">
                <div class="col-md-4">
                    <label class="form-label">Origin</label>
                    <input type="text" class="form-control" @bind="newShipment.Origin" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Destination</label>
                    <input type="text" class="form-control" @bind="newShipment.Destination" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Recipient</label>
                    <input type="text" class="form-control" @bind="newShipment.RecipientName" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Estimated Delivery (UTC)</label>
                    <input type="datetime-local" class="form-control" @bind="estimatedDelivery" />
                </div>
                <div class="col-md-8">
                    <label class="form-label">Notes</label>
                    <input type="text" class="form-control" @bind="newShipment.Notes" />
                </div>
            </div>
            <div class="mt-3">
                <button class="btn btn-primary me-2" @onclick="CreateShipment" disabled="@isCreating">
                    @(isCreating ? "Creating..." : "Create")
                </button>
                <button class="btn btn-secondary" @onclick="() => showCreateForm = false">Cancel</button>
            </div>
            @if (createError is not null)
            {
                <div class="alert alert-danger mt-2">@createError</div>
            }
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Recipient</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var s in FilteredShipments)
            {
                <tr>
                    <td><code>@s.TrackingNumber</code></td>
                    <td>@s.Origin</td>
                    <td>@s.Destination</td>
                    <td>@s.RecipientName</td>
                    <td><span class="badge @StatusBadgeClass(s.Status)">@s.Status</span></td>
                    <td>@(s.EstimatedDeliveryUtc?.ToString("MMM dd, yyyy") ?? "—")</td>
                    <td>
                        @if (s.Status != ShipmentStatus.Delivered && s.Status != ShipmentStatus.Cancelled)
                        {
                            <select class="form-select form-select-sm d-inline-block w-auto"
                                    @onchange="e => UpdateStatus(s, e)">
                                <option value="">Change status…</option>
                                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                {
                                    if (status != s.Status)
                                    {
                                        <option value="@((int)status)">@status</option>
                                    }
                                }
                            </select>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>

    @if (!FilteredShipments.Any())
    {
        <p class="text-muted">No shipments match your filter.</p>
    }
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = string.Empty;
    private bool showCreateForm;
    private bool isCreating;
    private string? createError;
    private ShipmentDto newShipment = new();
    private DateTime? estimatedDelivery;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments?.Where(s =>
            string.IsNullOrWhiteSpace(filterText) ||
            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.RecipientName.Contains(filterText, StringComparison.OrdinalIgnoreCase))
        ?? [];

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm()
    {
        newShipment = new ShipmentDto();
        estimatedDelivery = DateTime.UtcNow.AddDays(5);
        createError = null;
        showCreateForm = true;
    }

    private async Task CreateShipment()
    {
        if (string.IsNullOrWhiteSpace(newShipment.Origin) ||
            string.IsNullOrWhiteSpace(newShipment.Destination) ||
            string.IsNullOrWhiteSpace(newShipment.RecipientName))
        {
            createError = "Origin, Destination, and Recipient are required.";
            return;
        }

        isCreating = true;
        createError = null;
        try
        {
            newShipment.EstimatedDeliveryUtc = estimatedDelivery;
            await ShipmentService.CreateShipmentAsync(newShipment);
            showCreateForm = false;
            shipments = await ShipmentService.GetAllShipmentsAsync();
        }
        catch (Exception ex)
        {
            createError = $"Failed to create shipment: {ex.Message}";
        }
        finally
        {
            isCreating = false;
        }
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (e.Value is string val && int.TryParse(val, out var statusInt))
        {
            var newStatus = (ShipmentStatus)statusInt;
            await ShipmentService.UpdateStatusAsync(shipment.Id, new UpdateShipmentStatusRequest
            {
                NewStatus = newStatus
            });
            shipment.Status = newStatus;
        }
    }

    private static string StatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g., SHP-20260501-1001)"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="Search" disabled="@isSearching">
                @(isSearching ? "Searching..." : "Track")
            </button>
        </div>
    </div>
</div>

@if (searched)
{
    @if (shipment is not null)
    {
        <div class="card">
            <div class="card-header d-flex justify-content-between">
                <strong>Tracking: @shipment.TrackingNumber</strong>
                <span class="badge @StatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span>
            </div>
            <div class="card-body">
                <div class="row">
                    <div class="col-md-6">
                        <dl>
                            <dt>Origin</dt>
                            <dd>@shipment.Origin</dd>
                            <dt>Destination</dt>
                            <dd>@shipment.Destination</dd>
                            <dt>Recipient</dt>
                            <dd>@shipment.RecipientName</dd>
                        </dl>
                    </div>
                    <div class="col-md-6">
                        <dl>
                            <dt>Created</dt>
                            <dd>@shipment.CreatedAtUtc.ToString("MMMM dd, yyyy HH:mm") UTC</dd>
                            <dt>Estimated Delivery</dt>
                            <dd>
                                @if (shipment.EstimatedDeliveryUtc.HasValue)
                                {
                                    <span class="fw-bold text-primary">
                                        @shipment.EstimatedDeliveryUtc.Value.ToString("MMMM dd, yyyy")
                                    </span>
                                    @if (shipment.Status != ShipmentStatus.Delivered && shipment.Status != ShipmentStatus.Cancelled)
                                    {
                                        var daysLeft = (shipment.EstimatedDeliveryUtc.Value.Date - DateTime.UtcNow.Date).Days;
                                        <br />
                                        @if (daysLeft > 0)
                                        {
                                            <small class="text-muted">(@daysLeft day(s) remaining)</small>
                                        }
                                        else if (daysLeft == 0)
                                        {
                                            <small class="text-success">(Arriving today!)</small>
                                        }
                                        else
                                        {
                                            <small class="text-danger">(Overdue by @Math.Abs(daysLeft) day(s))</small>
                                        }
                                    }
                                }
                                else
                                {
                                    <span class="text-muted">Not yet determined</span>
                                }
                            </dd>
                        </dl>
                    </div>
                </div>

                @if (!string.IsNullOrEmpty(shipment.Notes))
                {
                    <div class="alert alert-light mt-2">
                        <strong>Notes:</strong> @shipment.Notes
                    </div>
                }

                <!-- Status progress bar -->
                <div class="mt-3">
                    <h6>Shipment Progress</h6>
                    <div class="progress" style="height: 30px;">
                        <div class="progress-bar @ProgressBarClass(shipment.Status)"
                             role="progressbar"
                             style="width: @ProgressPercent(shipment.Status)%"
                             aria-valuenow="@ProgressPercent(shipment.Status)"
                             aria-valuemin="0" aria-valuemax="100">
                            @shipment.Status
                        </div>
                    </div>
                </div>
            </div>
        </div>
    }
    else
    {
        <div class="alert alert-warning">
            No shipment found with tracking number <strong>@searchedNumber</strong>. Please check the number and try again.
        </div>
    }
}

@code {
    private string trackingNumber = string.Empty;
    private string searchedNumber = string.Empty;
    private ShipmentDto? shipment;
    private bool searched;
    private bool isSearching;

    private async Task Search()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber))
            return;

        isSearching = true;
        searched = false;
        try
        {
            searchedNumber = trackingNumber.Trim();
            shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchedNumber);
            searched = true;
        }
        finally
        {
            isSearching = false;
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await Search();
    }

    private static string StatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };

    private static int ProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Cancelled => 100,
        _ => 0
    };

    private static string ProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-primary"
    };
}

